/**
 * Injectable copy of styles.css. Keep in sync with scripts/sync-ui-css.mjs.
 */

export const GF_UI_CSS = "/*\n * Gotcha Force — shared UI styles for the 1-to-1 recreation component library.\n *\n * All classes are prefixed `gf-` to stay scoped. Palette + type feel are pulled\n * from the real captured reference screens in apps/game/reference/captures/.\n * Reference real extracted art via /ui/... public paths (see ASSETS const in TS).\n *\n * Injected automatically by ui/index.ts (ensureStyles); also importable directly\n * by a bundler that handles CSS imports.\n */\n\n:root {\n  /* Core palette sampled from the reference captures. */\n  --gf-yellow: #ffd21e;          /* SELECT DIFFICULTY title fill */\n  --gf-yellow-deep: #f5a800;     /* WIN gold */\n  --gf-outline: #2a2150;         /* dark title/text outline (purple-navy) */\n  --gf-green: #46c828;           /* ALLY meter / FIGHT ALONE ring / A button */\n  --gf-green-deep: #1f8a14;\n  --gf-red: #e8231b;             /* ENEMY meter / B button / INSANE pad */\n  --gf-red-deep: #a40d0d;\n  --gf-blue-pill: #5b9bd5;       /* results row pills */\n  --gf-blue-pill-deep: #2f6db0;\n  --gf-orange: #ff7a18;          /* TUFF pad / value numbers */\n  --gf-cyan: #34e0d8;            /* reload bar */\n  --gf-panel: #d9d9d9;           /* light HUD panel */\n  --gf-edit-purple: #6b4ad0;     /* pause box border / force ring */\n  --gf-text-cream: #fff4d8;\n  --gf-text-light: #eef4ff;\n}\n\n/* Generic full-screen menu surface that hosts a screen component. */\n.gf-screen {\n  position: relative;\n  width: 100%;\n  height: 100%;\n  min-height: 100%;\n  box-sizing: border-box;\n  overflow: hidden;\n  color: var(--gf-text-light);\n  font-family: \"Trebuchet MS\", \"Segoe UI\", Arial, sans-serif;\n  font-weight: 800;\n  letter-spacing: 0.02em;\n  user-select: none;\n  -webkit-user-select: none;\n}\n\n.gf-ui-scene {\n  position: absolute;\n  inset: 0;\n  z-index: 1;\n  pointer-events: none;\n}\n.gf-ui-scene-canvas {\n  display: block;\n  width: 100%;\n  height: 100%;\n}\n\n/* Gridded radial backdrop used by the menu screens (difficulty/players/force). */\n.gf-grid-bg {\n  position: absolute;\n  inset: 0;\n  background:\n    radial-gradient(circle at 50% 42%, rgba(255, 255, 255, 0.35), transparent 60%),\n    repeating-linear-gradient(0deg, rgba(255, 255, 255, 0.08) 0 1px, transparent 1px 34px),\n    repeating-linear-gradient(90deg, rgba(255, 255, 255, 0.08) 0 1px, transparent 1px 34px);\n  background-color: var(--gf-screen-bg, #2f7fd0);\n}\n.gf-grid-bg.gf-bg-blue { --gf-screen-bg: #2f7fd0; }\n.gf-grid-bg.gf-bg-green { --gf-screen-bg: #4caa2f; }\n.gf-grid-bg.gf-bg-purple { --gf-screen-bg: #8b4fb5; }\n.gf-grid-bg.gf-bg-gold { --gf-screen-bg: #f3a312; }\n\n.gf-vsel-real-scene {\n  opacity: 0.24;\n  transform: scale(1.06);\n  filter: drop-shadow(0 20px 18px rgba(0, 0, 0, 0.32));\n}\n\n/* Chunky outlined arcade title (SELECT DIFFICULTY, SELECT A FORCE, ...). */\n.gf-title {\n  position: relative;\n  z-index: 2;\n  text-align: center;\n  margin: 0;\n  padding-top: 0.6em;\n  font-size: clamp(22px, 4.4vw, 40px);\n  color: var(--gf-yellow);\n  letter-spacing: 0.06em;\n  text-transform: uppercase;\n  -webkit-text-stroke: 2px var(--gf-outline);\n  paint-order: stroke fill;\n  text-shadow: 0 4px 0 rgba(0, 0, 0, 0.35);\n}\n\n.gf-row {\n  position: relative;\n  z-index: 2;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: clamp(16px, 5vw, 64px);\n}\n\n/* Bottom button legend shared by menu screens. */\n.gf-legend {\n  position: absolute;\n  left: 0;\n  right: 0;\n  bottom: 18px;\n  z-index: 3;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: clamp(20px, 6vw, 64px);\n  font-size: clamp(13px, 2vw, 18px);\n}\n.gf-legend-item {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  color: #ffffff;\n  text-shadow: 0 2px 0 rgba(0, 0, 0, 0.45);\n}\n\n/* The round face-button glyphs (A green / B red / X grey / Y / START). */\n.gf-btn {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  width: 1.7em;\n  height: 1.7em;\n  border-radius: 50%;\n  font-size: 0.9em;\n  color: #ffffff;\n  font-weight: 900;\n  box-shadow: inset 0 -3px 0 rgba(0, 0, 0, 0.35), 0 2px 3px rgba(0, 0, 0, 0.4);\n}\n.gf-btn-a { background: radial-gradient(circle at 35% 30%, #6fe24a, var(--gf-green-deep)); }\n.gf-btn-b { background: radial-gradient(circle at 35% 30%, #ff5a4f, var(--gf-red-deep)); }\n.gf-btn-x { background: radial-gradient(circle at 35% 30%, #cfd3da, #7d828c); color: #2a2150; }\n.gf-btn-y { background: radial-gradient(circle at 35% 30%, #6fc3ff, #2f6db0); }\n.gf-btn-start { background: radial-gradient(circle at 35% 30%, #cfd3da, #7d828c); color: #2a2150; font-size: 0.62em; }\n\n.gf-bitmap-text {\n  display: inline-flex;\n  align-items: center;\n  gap: 1px;\n  image-rendering: pixelated;\n  font-size: 0;\n}\n.gf-bitmap-glyph,\n.gf-bitmap-space {\n  display: inline-block;\n  width: 8px;\n  height: 8px;\n  flex: 0 0 auto;\n}\n.gf-bitmap-glyph {\n  background-repeat: no-repeat;\n  background-size: 128px 128px;\n}\n.gf-bitmap-fallback {\n  display: inline-block;\n  font-size: 8px;\n  line-height: 8px;\n}\n\n/* Generic option tile used by difficulty + players screens. */\n.gf-option {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 6px;\n  cursor: pointer;\n  background: none;\n  border: none;\n  color: inherit;\n  font: inherit;\n  padding: 8px;\n  transition: transform 0.12s ease;\n}\n.gf-option:hover { transform: translateY(-2px); }\n.gf-option.gf-selected { transform: scale(1.06); }\n\n/* The colored oval \"pad\" that selected items sit on. */\n.gf-pad {\n  position: relative;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  width: clamp(110px, 22vw, 170px);\n  height: clamp(110px, 22vw, 170px);\n  border-radius: 50%;\n}\n.gf-option.gf-selected .gf-pad {\n  box-shadow: 0 0 0 6px rgba(0, 0, 0, 0.85), 0 0 0 10px rgba(255, 255, 255, 0.25);\n}\n\n.gf-energy-label { font-size: 0.7em; color: #ffffff; text-shadow: 0 1px 0 #000; }\n.gf-energy-num {\n  font-size: clamp(26px, 6vw, 44px);\n  line-height: 0.9;\n  color: #ffffff;\n  -webkit-text-stroke: 1.5px var(--gf-outline);\n  paint-order: stroke fill;\n}\n.gf-energy-name {\n  font-size: clamp(13px, 2.4vw, 20px);\n  -webkit-text-stroke: 1px var(--gf-outline);\n  paint-order: stroke fill;\n}\n.gf-name-normal { color: var(--gf-red); }\n.gf-name-tuff { color: #ffffff; }\n.gf-name-insane { color: #ffffff; }\n\n/* Label pill under the player-count silhouettes. */\n.gf-pill {\n  margin-top: 6px;\n  padding: 4px 18px;\n  border-radius: 999px;\n  background: linear-gradient(#7fc1f0, var(--gf-blue-pill-deep));\n  color: #ffffff;\n  font-size: clamp(13px, 2.2vw, 18px);\n  -webkit-text-stroke: 0.6px var(--gf-outline);\n  paint-order: stroke fill;\n  box-shadow: inset 0 -2px 0 rgba(0, 0, 0, 0.3);\n}\n.gf-option.gf-selected .gf-pill { background: linear-gradient(#9ad4ff, #2f6db0); }\n\n/* ============================ MAIN MENU ============================ */\n.gf-mainmenu {\n  background: #6eb6d7;\n}\n.gf-mainmenu-frame {\n  position: absolute;\n  left: 50%;\n  top: 50%;\n  width: min(100%, calc(100vh * 4 / 3));\n  max-height: 100%;\n  aspect-ratio: 4 / 3;\n  transform: translate(-50%, -50%);\n  overflow: hidden;\n  background: #58a9ca;\n  box-shadow: 0 0 0 1px rgba(0, 0, 0, 0.2);\n}\n.gf-mainmenu-scene {\n  opacity: 0;\n  transform: scale(1.02);\n  transition: opacity var(--gf-native-tween-ms, 167ms) linear;\n}\n.gf-mainmenu[data-native-capture=\"false\"] .gf-mainmenu-scene {\n  opacity: 0.32;\n}\n.gf-mainmenu-desk {\n  position: absolute;\n  inset: 0;\n  z-index: 1;\n  background-size: 100% 100%;\n  background-position: center;\n  background-repeat: no-repeat;\n  image-rendering: pixelated;\n  transition:\n    opacity var(--gf-native-tween-ms, 167ms) linear,\n    filter var(--gf-native-tween-ms, 167ms) linear;\n}\n.gf-mainmenu[data-native-capture=\"false\"] .gf-mainmenu-desk {\n  opacity: 0.88;\n  filter: saturate(0.96) brightness(0.94);\n}\n.gf-mainmenu-desk::after {\n  content: \"\";\n  position: absolute;\n  inset: 0;\n  background: linear-gradient(180deg, rgba(255, 255, 255, 0.04), rgba(0, 0, 0, 0.1));\n  pointer-events: none;\n}\n.gf-mainmenu-ring {\n  position: absolute;\n  inset: 0;\n  z-index: 2;\n}\n.gf-menu-item {\n  position: absolute;\n  transform: translate(-50%, -50%);\n  cursor: pointer;\n  background: none;\n  border: none;\n  padding: 0;\n  opacity: 0;\n  outline: none;\n}\n.gf-menu-item:focus-visible {\n  opacity: 1;\n  border-radius: 50%;\n  box-shadow: 0 0 0 3px rgba(255, 255, 255, 0.86), 0 0 0 7px rgba(232, 35, 27, 0.55);\n}\n.gf-menu-item.gf-selected:focus-visible {\n  box-shadow: 0 0 0 4px rgba(255, 255, 255, 0.92), 0 0 0 9px rgba(232, 35, 27, 0.72);\n}\n.gf-menu-cursor {\n  position: absolute;\n  transform: translate(-50%, -50%);\n  pointer-events: none;\n  border-radius: 50%;\n  opacity: 0;\n  transition:\n    left var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\n    top var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\n    width var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\n    height var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\n    opacity var(--gf-native-tween-ms, 167ms) linear;\n}\n.gf-mainmenu[data-native-capture=\"false\"] .gf-menu-cursor {\n  opacity: 0.9;\n}\n.gf-menu-cursor::before {\n  content: \"\";\n  position: absolute;\n  left: 50%;\n  top: 50%;\n  width: min(124px, 84%);\n  aspect-ratio: 1;\n  transform: translate(-50%, -50%);\n  border-radius: 50%;\n  background:\n    conic-gradient(from 11deg, #7e160f 0 8deg, transparent 8deg 22deg),\n    radial-gradient(circle at 35% 30%, #ff8a4a, var(--gf-red));\n  box-shadow:\n    inset 0 -4px 0 rgba(0, 0, 0, 0.38),\n    inset 0 0 0 11px rgba(255, 255, 255, 0.22),\n    0 0 0 5px rgba(255, 255, 255, 0.86),\n    0 0 0 12px rgba(232, 35, 27, 0.9),\n    0 8px 10px rgba(0, 0, 0, 0.42);\n  animation: gf-gear-spin 6s linear infinite;\n}\n@keyframes gf-gear-spin { to { transform: translate(-50%, -50%) rotate(360deg); } }\n.gf-mainmenu-selected-proxy {\n  position: absolute;\n  transform: translate(-50%, -50%);\n  display: grid;\n  place-items: center;\n  pointer-events: none;\n  opacity: 0;\n  transition:\n    left var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\n    top var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\n    width var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\n    height var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\n    opacity var(--gf-native-tween-ms, 167ms) linear,\n    transform var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1);\n}\n.gf-mainmenu[data-native-capture=\"false\"] .gf-mainmenu-selected-proxy {\n  opacity: 1;\n}\n.gf-mainmenu[data-transitioning=\"true\"] .gf-mainmenu-selected-proxy {\n  transform: translate(-50%, -50%) scale(1.08);\n}\n.gf-mainmenu-selected-label {\n  position: relative;\n  z-index: 2;\n  color: var(--gf-yellow);\n  font-size: clamp(22px, 4vw, 58px);\n  line-height: 0.86;\n  letter-spacing: 0;\n  white-space: nowrap;\n  -webkit-text-stroke: clamp(2px, 0.32vw, 5px) #071126;\n  paint-order: stroke fill;\n  text-shadow:\n    0 3px 0 #ffffff,\n    0 7px 0 rgba(0, 0, 0, 0.52);\n}\n.gf-mainmenu-option-texture {\n  position: absolute;\n  right: 3%;\n  top: 3%;\n  width: min(24%, 300px);\n  image-rendering: pixelated;\n  opacity: 0;\n  pointer-events: none;\n  filter: drop-shadow(0 5px 0 rgba(0, 0, 0, 0.35));\n  transition: opacity var(--gf-native-tween-ms, 167ms) linear;\n}\n.gf-mainmenu[data-mode=\"option\"] .gf-mainmenu-option-texture {\n  opacity: 0.88;\n}\n\n/* ============================ LOAD BOX DATA ============================ */\n.gf-load-box { background: #f3a312; }\n.gf-load-title {\n  position: absolute;\n  top: 17%;\n  left: 0;\n  right: 0;\n  font-size: clamp(34px, 6.8vw, 72px);\n}\n.gf-load-rule {\n  position: absolute;\n  left: 17%;\n  right: 17%;\n  top: 34%;\n  height: 6px;\n  border-radius: 999px;\n  background: #ffffff;\n  box-shadow: 0 3px 0 rgba(0, 0, 0, 0.35);\n}\n.gf-load-copy {\n  position: absolute;\n  left: 12%;\n  right: 12%;\n  top: 40%;\n  z-index: 2;\n  color: #ffffff;\n  text-align: center;\n  font-size: clamp(18px, 2.9vw, 34px);\n  line-height: 1.45;\n  -webkit-text-stroke: 1.5px #89420e;\n  paint-order: stroke fill;\n  text-shadow: 0 3px 0 rgba(0, 0, 0, 0.28);\n}\n.gf-inline-a {\n  display: inline-grid;\n  place-items: center;\n  width: 1.3em;\n  height: 1.3em;\n  border-radius: 50%;\n  margin: 0 0.12em;\n  color: #ffffff;\n  background: #18a949;\n  -webkit-text-stroke: 0;\n  box-shadow: inset 0 -3px 0 rgba(0, 0, 0, 0.25), 0 2px 0 rgba(0, 0, 0, 0.25);\n}\n.gf-box-model {\n  position: absolute;\n  left: 50%;\n  bottom: 12%;\n  width: min(44vw, 420px);\n  height: min(28vw, 270px);\n  transform: translateX(-50%);\n  z-index: 2;\n}\n.gf-box-model .gf-ui-scene-canvas {\n  display: block;\n  width: 100%;\n  height: 100%;\n  filter: drop-shadow(0 28px 20px rgba(0, 0, 0, 0.38));\n}\n\n/* ============================ SELECT A FORCE ============================ */\n.gf-select-force { background: #8b4fb5; }\n.gf-select-entry-scene {\n  opacity: 0.46;\n  transform: scale(1.04);\n  z-index: 1;\n}\n.gf-select-entry-scene .gf-ui-scene-canvas {\n  filter: drop-shadow(0 18px 18px rgba(0, 0, 0, 0.32));\n}\n.gf-select-entry-sheet {\n  position: absolute;\n  left: 2%;\n  top: 2%;\n  width: min(16vw, 118px);\n  max-height: 18vh;\n  object-fit: contain;\n  image-rendering: pixelated;\n  opacity: 0.92;\n  z-index: 2;\n}\n.gf-select-platform {\n  position: absolute;\n  left: 50%;\n  top: 47%;\n  width: min(45vw, 420px);\n  height: min(17vw, 150px);\n  transform: translate(-50%, -50%) perspective(720px) rotateX(62deg);\n  border-radius: 50%;\n  background:\n    radial-gradient(circle at 50% 34%, rgba(255, 255, 255, 0.85), rgba(255, 255, 255, 0.1) 30%, transparent 31%),\n    radial-gradient(ellipse at center, #80d85d 0 46%, #378a34 47% 67%, #145e2f 68% 100%);\n  box-shadow: 0 18px 0 #85471d, 0 28px 24px rgba(0, 0, 0, 0.35);\n  z-index: 2;\n}\n.gf-select-face,\n.gf-select-mini {\n  position: absolute;\n  left: 50%;\n  top: 0;\n  max-width: 42%;\n  max-height: 160%;\n  object-fit: contain;\n  transform: translate(-50%, -74%) rotateX(-62deg) scale(2.1);\n  image-rendering: pixelated;\n  filter: drop-shadow(0 10px 0 rgba(0, 0, 0, 0.32));\n}\n.gf-select-borg-scene {\n  position: absolute;\n  left: 50%;\n  bottom: 34%;\n  width: min(30vw, 280px);\n  height: min(38vw, 340px);\n  transform: translate(-50%, 0) rotateX(-62deg);\n  pointer-events: none;\n  filter: drop-shadow(0 14px 0 rgba(0, 0, 0, 0.32));\n}\n.gf-select-cost {\n  position: absolute;\n  left: 10%;\n  bottom: 24%;\n  z-index: 3;\n  display: grid;\n  grid-template-columns: auto auto;\n  align-items: baseline;\n  gap: 12px;\n  color: #ffffff;\n  -webkit-text-stroke: 1.5px #2a1f46;\n  paint-order: stroke fill;\n  text-shadow: 0 3px 0 rgba(0, 0, 0, 0.38);\n}\n.gf-select-cost-label {\n  font-size: clamp(20px, 3vw, 36px);\n  color: var(--gf-yellow);\n}\n.gf-select-cost-value {\n  font-size: clamp(44px, 8vw, 90px);\n}\n.gf-select-name {\n  position: absolute;\n  right: 7%;\n  bottom: 21%;\n  z-index: 3;\n  display: grid;\n  grid-template-columns: auto minmax(160px, 448px);\n  grid-template-areas:\n    \"no banner\"\n    \"force force\"\n    \"limit limit\";\n  gap: 6px 14px;\n  align-items: center;\n  min-width: min(48vw, 520px);\n  color: #ffffff;\n}\n.gf-select-no {\n  grid-area: no;\n  font-size: clamp(18px, 2.4vw, 28px);\n  -webkit-text-stroke: 1.25px #2a1f46;\n  paint-order: stroke fill;\n}\n.gf-select-banner {\n  grid-area: banner;\n  width: 100%;\n  max-width: 448px;\n  image-rendering: pixelated;\n  filter: drop-shadow(0 3px 0 rgba(0, 0, 0, 0.35));\n}\n.gf-select-force-name {\n  grid-area: force;\n  font-size: clamp(22px, 3.6vw, 44px);\n  color: var(--gf-yellow);\n  -webkit-text-stroke: 1.8px #2a1f46;\n  paint-order: stroke fill;\n  text-shadow: 0 3px 0 rgba(0, 0, 0, 0.35);\n}\n.gf-select-limit {\n  grid-area: limit;\n  justify-self: end;\n  font-size: clamp(14px, 2vw, 22px);\n  color: #dff6ff;\n  -webkit-text-stroke: 1px #2a1f46;\n  paint-order: stroke fill;\n}\n\n/* ============================ BATTLE INTRO ============================ */\n.gf-battle-intro {\n  background:\n    radial-gradient(circle at 50% 50%, rgba(255, 255, 255, 0.08), transparent 52%),\n    linear-gradient(90deg, rgba(20, 78, 156, 0.82), rgba(137, 56, 155, 0.72));\n  pointer-events: auto;\n}\n.gf-brief-real-scene {\n  opacity: 0.34;\n  transform: scale(1.08);\n  filter: drop-shadow(0 18px 18px rgba(0, 0, 0, 0.35));\n}\n.gf-brief-vs-sheet,\n.gf-brief-label-sheet {\n  position: absolute;\n  image-rendering: pixelated;\n  pointer-events: none;\n  opacity: 0.22;\n  z-index: 1;\n}\n.gf-brief-vs-sheet {\n  left: 50%;\n  top: 50%;\n  width: min(36vw, 300px);\n  transform: translate(-50%, -50%) scale(1.6);\n}\n.gf-brief-label-sheet {\n  right: 2%;\n  top: 2%;\n  width: min(24vw, 190px);\n}\n.gf-brief-title {\n  position: absolute;\n  left: 50%;\n  top: 5%;\n  transform: translateX(-50%);\n  margin: 0;\n  z-index: 3;\n  width: min(86%, 860px);\n  color: var(--gf-yellow);\n  text-align: center;\n  font-size: clamp(24px, 4.2vw, 50px);\n  -webkit-text-stroke: 2px var(--gf-outline);\n  paint-order: stroke fill;\n  text-shadow: 0 4px 0 rgba(0, 0, 0, 0.4);\n}\n.gf-brief-side {\n  position: absolute;\n  top: 25%;\n  z-index: 3;\n  width: min(32vw, 300px);\n  min-height: 42%;\n  display: grid;\n  justify-items: center;\n  align-content: start;\n  gap: 10px;\n}\n.gf-brief-player { left: 6%; }\n.gf-brief-enemy { right: 6%; }\n.gf-brief-icon,\n.gf-brief-emblem {\n  width: min(24vw, 220px);\n  aspect-ratio: 1;\n  object-fit: contain;\n  image-rendering: pixelated;\n  filter: drop-shadow(0 8px 0 rgba(0, 0, 0, 0.35));\n}\n.gf-brief-emblem {\n  border-radius: 50%;\n  background: radial-gradient(circle, var(--gf-yellow), var(--gf-red));\n}\n.gf-brief-energy,\n.gf-brief-name {\n  padding: 4px 16px;\n  border-radius: 999px;\n  color: #ffffff;\n  font-size: clamp(15px, 2.2vw, 24px);\n  -webkit-text-stroke: 1px var(--gf-outline);\n  paint-order: stroke fill;\n  text-shadow: 0 2px 0 rgba(0, 0, 0, 0.4);\n  box-shadow: inset 0 -3px 0 rgba(0, 0, 0, 0.22), 0 3px 0 rgba(0, 0, 0, 0.24);\n}\n.gf-brief-energy-player { background: linear-gradient(#3ea6ff, #1262c8); }\n.gf-brief-energy-enemy { background: linear-gradient(#ff5d4c, #b81d1a); }\n.gf-brief-name {\n  max-width: 100%;\n  background: linear-gradient(#fff2a8, #dc9f18);\n  color: #ffffff;\n  text-align: center;\n  white-space: normal;\n}\n.gf-brief-vs {\n  position: absolute;\n  left: 50%;\n  top: 42%;\n  transform: translate(-50%, -50%) rotate(-8deg);\n  z-index: 4;\n  color: #ffffff;\n  font-size: clamp(46px, 9vw, 106px);\n  -webkit-text-stroke: 3px var(--gf-red);\n  paint-order: stroke fill;\n  text-shadow: 0 7px 0 rgba(0, 0, 0, 0.35);\n}\n.gf-brief-preview {\n  position: absolute;\n  left: 50%;\n  bottom: 16%;\n  transform: translateX(-50%);\n  z-index: 2;\n  width: min(44vw, 470px);\n  height: min(18vw, 170px);\n  border: 5px solid rgba(255, 255, 255, 0.8);\n  border-radius: 10px;\n  background: rgba(0, 0, 0, 0.2);\n  box-shadow: inset 0 0 0 3px rgba(0, 0, 0, 0.28), 0 8px 0 rgba(0, 0, 0, 0.35);\n}\n.gf-brief-objective {\n  position: absolute;\n  left: 50%;\n  bottom: -22px;\n  transform: translateX(-50%);\n  width: max-content;\n  max-width: 92vw;\n  padding: 7px 24px;\n  border-radius: 999px;\n  background: linear-gradient(#ffd969, #e9a51a);\n  color: #ffffff;\n  font-size: clamp(14px, 2vw, 24px);\n  -webkit-text-stroke: 1px #754216;\n  paint-order: stroke fill;\n  box-shadow: 0 3px 0 rgba(0, 0, 0, 0.35);\n}\n\n/* ============================ FORCE BUILDER ============================ */\n.gf-force { display: grid; grid-template-columns: 1fr minmax(280px, 42%); gap: 12px; padding: 12px; box-sizing: border-box; height: 100%; }\n.gf-force-unitall-atlas {\n  position: absolute;\n  left: 14px;\n  top: 54px;\n  width: min(46vw, 420px);\n  max-height: calc(100% - 118px);\n  object-fit: cover;\n  object-position: top left;\n  opacity: 0.18;\n  image-rendering: pixelated;\n  pointer-events: none;\n}\n.gf-force-edit-tab {\n  display: inline-flex;\n  align-items: center;\n  gap: 14px;\n  align-self: start;\n  padding: 6px 22px;\n  border-radius: 999px;\n  background: linear-gradient(#5f96d8, #2f6db0);\n  border: 2px solid #9fc8f0;\n  color: #fff;\n  font-size: 18px;\n  letter-spacing: 0.08em;\n}\n.gf-force-left { position: relative; display: flex; flex-direction: column; gap: 10px; min-height: 0; }\n.gf-force-left > :not(.gf-force-unitall-atlas) { position: relative; z-index: 1; }\n.gf-force-grid {\n  flex: 1;\n  min-height: 0;\n  overflow-y: auto;\n  display: grid;\n  grid-template-columns: repeat(auto-fill, minmax(58px, 1fr));\n  gap: 6px;\n  padding: 10px;\n  border-radius: 10px;\n  background: linear-gradient(#1d3a63, #12263f);\n  border: 2px solid #2f5e96;\n}\n.gf-borg-cell {\n  position: relative;\n  aspect-ratio: 1;\n  display: grid;\n  place-items: center;\n  border-radius: 8px;\n  background: #e9eef5;\n  border: 2px solid #b9c4d3;\n  cursor: pointer;\n  overflow: hidden;\n  padding: 0;\n}\n.gf-borg-cell img { width: 100%; height: 100%; object-fit: contain; image-rendering: pixelated; }\n.gf-borg-cell.gf-in-force { border-color: var(--gf-yellow); box-shadow: 0 0 0 2px var(--gf-yellow) inset; }\n.gf-borg-cell.gf-disabled { opacity: 0.35; cursor: not-allowed; }\n.gf-borg-cell .gf-cost-tag {\n  position: absolute;\n  bottom: 0;\n  right: 0;\n  font-size: 9px;\n  background: rgba(0, 0, 0, 0.7);\n  color: #ffd21e;\n  padding: 0 3px;\n  border-top-left-radius: 4px;\n}\n.gf-borg-cell .gf-new-badge {\n  position: absolute;\n  top: 0;\n  left: 0;\n  font-size: 8px;\n  color: var(--gf-yellow);\n  background: var(--gf-red);\n  padding: 0 3px;\n  border-bottom-right-radius: 4px;\n  -webkit-text-stroke: 0.4px var(--gf-outline);\n}\n\n.gf-force-right {\n  position: relative;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  border-radius: 10px;\n  background: radial-gradient(circle at 60% 50%, #3a2a6e, #1c1340);\n  border: 3px solid var(--gf-edit-purple);\n  padding: 10px;\n  min-height: 0;\n}\n.gf-force-banner {\n  align-self: stretch;\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  padding: 4px 10px;\n  border-radius: 999px;\n  background: linear-gradient(#cfd3da, #9aa0ab);\n  border: 2px solid #eef2f7;\n  margin-bottom: 8px;\n}\n.gf-force-banner img { height: 26px; image-rendering: pixelated; }\n.gf-force-banner .gf-force-banner-name {\n  font-size: 16px;\n  color: #2f6db0;\n  -webkit-text-stroke: 0.6px #fff;\n  paint-order: stroke fill;\n  letter-spacing: 0.06em;\n}\n.gf-force-ring {\n  position: relative;\n  width: 100%;\n  flex: 1;\n  min-height: 200px;\n}\n.gf-slot {\n  position: absolute;\n  width: 30px;\n  height: 34px;\n  transform: translate(-50%, -50%);\n  display: grid;\n  place-items: center;\n  cursor: pointer;\n  clip-path: polygon(50% 0, 100% 25%, 100% 75%, 50% 100%, 0 75%, 0 25%);\n  background: linear-gradient(#ffd86b, #f5a800);\n  border: 0;\n  font-size: 11px;\n  color: var(--gf-outline);\n  font-weight: 900;\n}\n.gf-slot.gf-slot-empty { background: linear-gradient(#5a4a8a, #34265f); color: rgba(255, 255, 255, 0.5); }\n.gf-slot.gf-slot-filled { box-shadow: 0 0 0 1px #fff; }\n.gf-slot.gf-slot-active { box-shadow: 0 0 0 2px var(--gf-red); }\n.gf-slot img { width: 88%; height: 88%; object-fit: contain; image-rendering: pixelated; }\n\n.gf-cost-panel {\n  position: absolute;\n  right: 6%;\n  top: 38%;\n  width: 46%;\n  background: linear-gradient(#e9eef5, #c6cedb);\n  border: 2px solid #fff;\n  border-radius: 8px;\n  padding: 6px 8px;\n  color: var(--gf-outline);\n  box-shadow: 0 4px 8px rgba(0, 0, 0, 0.5);\n}\n.gf-cost-panel .gf-cost-line {\n  display: flex;\n  justify-content: space-between;\n  align-items: baseline;\n  gap: 8px;\n  font-size: 13px;\n}\n.gf-cost-panel .gf-cost-total {\n  border-bottom: 2px solid #9aa0ab;\n  padding-bottom: 4px;\n  margin-bottom: 4px;\n}\n.gf-cost-panel .gf-cost-val { font-size: 18px; -webkit-text-stroke: 0.4px #fff; paint-order: stroke fill; }\n.gf-cost-panel.gf-over .gf-cost-val.gf-remain { color: var(--gf-red); }\n\n/* ============================ BATTLE HUD ============================ */\n.gf-hud {\n  position: absolute;\n  inset: 0;\n  pointer-events: none;\n  font-family: \"Trebuchet MS\", \"Segoe UI\", Arial, sans-serif;\n  font-weight: 800;\n  color: #fff;\n  z-index: 10;\n}\n.gf-hud-meters { position: absolute; top: 12px; left: 12px; display: flex; flex-direction: column; gap: 8px; }\n.gf-meter { position: relative; width: 220px; height: 18px; display: flex; align-items: center; }\n.gf-meter-tab {\n  position: relative;\n  z-index: 2;\n  min-width: 38px;\n  height: 100%;\n  display: grid;\n  place-items: center;\n  padding: 0 6px;\n  font-size: 13px;\n  color: #fff;\n  -webkit-text-stroke: 0.5px #000;\n  paint-order: stroke fill;\n}\n.gf-meter-tab .gf-bitmap-text {\n  transform: scale(1.35);\n  transform-origin: center;\n  filter: drop-shadow(1px 1px 0 #000);\n}\n.gf-meter-ally .gf-meter-tab { background: var(--gf-green-deep); border-radius: 4px 0 0 4px; }\n.gf-meter-enemy .gf-meter-tab { background: var(--gf-red-deep); border-radius: 4px 0 0 4px; }\n.gf-meter-track {\n  position: relative;\n  flex: 1;\n  height: 100%;\n  background: rgba(0, 0, 0, 0.55);\n  /* zigzag/torn right end */\n  clip-path: polygon(0 0, 100% 0, 96% 25%, 100% 50%, 96% 75%, 100% 100%, 0 100%);\n  overflow: hidden;\n}\n.gf-meter-fill { position: absolute; inset: 0; transform-origin: left center; transition: transform 0.25s ease; }\n.gf-meter-ally .gf-meter-fill { background: linear-gradient(#7be85a, var(--gf-green)); }\n.gf-meter-enemy .gf-meter-fill { background: linear-gradient(#ff6a5f, var(--gf-red)); }\n.gf-meter-name {\n  position: absolute;\n  right: 8px;\n  top: 50%;\n  transform: translateY(-50%);\n  z-index: 2;\n  font-size: 12px;\n  letter-spacing: 0.1em;\n  -webkit-text-stroke: 0.5px #000;\n  paint-order: stroke fill;\n}\n.gf-meter-name .gf-bitmap-text {\n  transform: scale(1.25);\n  transform-origin: right center;\n  filter: drop-shadow(1px 1px 0 #000);\n}\n.gf-hud-alert {\n  position: absolute;\n  top: 14px;\n  left: 244px;\n  width: 26px;\n  height: 26px;\n  display: grid;\n  place-items: center;\n  border-radius: 50%;\n  background: var(--gf-yellow);\n  color: var(--gf-outline);\n  font-size: 18px;\n  border: 2px solid #fff;\n}\n.gf-hud-alert.gf-hidden { display: none; }\n.gf-hud-timer {\n  position: absolute;\n  top: 12px;\n  left: 50%;\n  transform: translateX(-50%);\n  min-width: 78px;\n  height: 24px;\n  display: grid;\n  place-items: center;\n  border-radius: 999px;\n  background: linear-gradient(#eef2f7, #9aa0ab);\n  border: 2px solid #ffffff;\n  box-shadow: inset 0 -3px 0 rgba(0, 0, 0, 0.24), 0 3px 0 rgba(0, 0, 0, 0.35);\n}\n.gf-hud-timer.gf-hidden { display: none; }\n.gf-hud-timer-text {\n  transform: scale(1.65);\n  transform-origin: center;\n  filter: drop-shadow(1px 1px 0 #000);\n}\n\n/* center lock-on reticle */\n.gf-hud-reticle {\n  position: absolute;\n  top: 44%;\n  left: 50%;\n  width: 78px;\n  height: 78px;\n  transform: translate(-50%, -50%);\n  display: grid;\n  place-items: center;\n  transition: opacity 0.15s ease;\n}\n.gf-hud-reticle.gf-hidden { opacity: 0; }\n.gf-reticle-ring {\n  position: absolute;\n  inset: 0;\n  border: 4px solid var(--gf-orange);\n  border-radius: 50%;\n  box-shadow: 0 0 0 2px rgba(0, 0, 0, 0.4);\n  animation: gf-reticle-spin 4s linear infinite;\n}\n@keyframes gf-reticle-spin { to { transform: rotate(360deg); } }\n.gf-reticle-tri { position: absolute; width: 0; height: 0; color: #3a7bd5; }\n\n/* bottom-left HP gauge */\n.gf-hud-hp {\n  position: absolute;\n  bottom: 16px;\n  left: 16px;\n  width: 92px;\n  height: 60px;\n  display: grid;\n  place-items: center;\n}\n.gf-hp-face-marker {\n  position: absolute;\n  left: -7px;\n  top: -9px;\n  width: 42px;\n  height: 42px;\n  object-fit: none;\n  object-position: 0 0;\n  image-rendering: pixelated;\n  filter: drop-shadow(0 2px 0 rgba(0, 0, 0, 0.4));\n}\n.gf-hp-ring { position: absolute; inset: 0; }\n.gf-hp-num {\n  position: relative;\n  z-index: 2;\n  font-size: 26px;\n  color: var(--gf-yellow);\n  -webkit-text-stroke: 1.4px var(--gf-outline);\n  paint-order: stroke fill;\n}\n.gf-hp-num.gf-bitmap-text {\n  transform: scale(2.6);\n  transform-origin: center;\n  filter: drop-shadow(1px 1px 0 var(--gf-outline));\n}\n.gf-hud-hp.gf-critical .gf-hp-num { color: #fff; }\n\n/* bottom-right weapon prompts */\n.gf-hud-weapon { position: absolute; bottom: 16px; right: 16px; display: flex; align-items: flex-end; gap: 14px; }\n.gf-weapon-x { display: grid; place-items: center; width: 56px; height: 56px; }\n.gf-weapon-x .gf-x-glyph {\n  position: relative;\n  z-index: 2;\n  width: 26px;\n  height: 26px;\n  display: grid;\n  place-items: center;\n  border-radius: 50%;\n  background: radial-gradient(circle at 35% 30%, #cfd3da, #7d828c);\n  color: var(--gf-outline);\n  font-size: 14px;\n  font-weight: 900;\n}\n.gf-button-letter {\n  transform: scale(1.6);\n  transform-origin: center;\n  filter: drop-shadow(1px 1px 0 rgba(255, 255, 255, 0.45));\n}\n.gf-cooldown-ring { position: absolute; inset: 0; }\n.gf-weapon-b { display: flex; align-items: center; gap: 6px; }\n.gf-b-track {\n  position: relative;\n  width: 70px;\n  height: 16px;\n  border-radius: 999px;\n  background: rgba(0, 0, 0, 0.55);\n  overflow: hidden;\n  display: flex;\n  align-items: center;\n  padding-left: 8px;\n}\n.gf-b-reload { position: absolute; left: 0; top: 0; bottom: 0; background: var(--gf-cyan); transition: width 0.2s ease; }\n.gf-b-ammo { position: relative; z-index: 2; color: var(--gf-yellow); font-size: 15px; -webkit-text-stroke: 1px var(--gf-outline); paint-order: stroke fill; }\n.gf-b-ammo.gf-bitmap-text {\n  transform: scale(1.5);\n  transform-origin: left center;\n  filter: drop-shadow(1px 1px 0 var(--gf-outline));\n}\n.gf-b-glyph {\n  width: 26px;\n  height: 26px;\n  display: grid;\n  place-items: center;\n  border-radius: 50%;\n  background: radial-gradient(circle at 35% 30%, #ff5a4f, var(--gf-red-deep));\n  color: #fff;\n  font-size: 14px;\n  font-weight: 900;\n}\n\n/* ============================ RESULTS ============================ */\n.gf-results { background: #6a3f2a; }\n.gf-results-backdrop {\n  position: absolute;\n  inset: 0;\n  z-index: 0;\n  width: 100%;\n  height: 100%;\n  object-fit: cover;\n  image-rendering: pixelated;\n}\n.gf-results::after {\n  content: \"\";\n  position: absolute;\n  inset: 0;\n  z-index: 1;\n  background: linear-gradient(90deg, rgba(0, 0, 0, 0.38), rgba(0, 0, 0, 0.08) 54%, rgba(0, 0, 0, 0.18));\n  pointer-events: none;\n}\n.gf-results-rows {\n  position: absolute;\n  left: 6%;\n  top: 10%;\n  width: 56%;\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n  z-index: 3;\n}\n.gf-result-row { display: flex; align-items: center; }\n.gf-result-pill {\n  flex: 1;\n  display: flex;\n  align-items: center;\n  padding: 6px 14px;\n  border-radius: 999px;\n  background: linear-gradient(#7fb4e6, var(--gf-blue-pill-deep));\n  border: 2px solid #bcdcff;\n  color: #fff;\n  font-size: clamp(11px, 1.8vw, 17px);\n  letter-spacing: 0.04em;\n  -webkit-text-stroke: 0.5px var(--gf-outline);\n  paint-order: stroke fill;\n  box-shadow: inset 0 -2px 0 rgba(0, 0, 0, 0.25);\n  text-transform: uppercase;\n}\n.gf-result-sub { background: linear-gradient(#9ec3e8, #4f7fb0); }\n.gf-result-grand .gf-result-pill { background: linear-gradient(#ffe27a, var(--gf-orange)); color: var(--gf-outline); }\n.gf-result-val {\n  margin-left: 12px;\n  min-width: 4ch;\n  text-align: right;\n  font-size: clamp(16px, 3vw, 26px);\n  color: #fff;\n  -webkit-text-stroke: 1px var(--gf-outline);\n  paint-order: stroke fill;\n}\n.gf-result-val.gf-neg { color: var(--gf-red); }\n.gf-results-verdict {\n  position: absolute;\n  left: 42%;\n  top: 44%;\n  transform: translate(-50%, -50%) rotate(-6deg);\n  z-index: 3;\n  font-size: clamp(48px, 12vw, 110px);\n  letter-spacing: 0.04em;\n}\n.gf-verdict-win { color: var(--gf-yellow); -webkit-text-stroke: 4px var(--gf-red); paint-order: stroke fill; text-shadow: 0 6px 0 rgba(0, 0, 0, 0.4); }\n.gf-verdict-lose {\n  left: 50%;\n  top: 36%;\n  width: min(68vw, 448px);\n  transform: translate(-50%, -50%) rotate(-3deg);\n}\n.gf-results-gameover {\n  display: block;\n  width: 100%;\n  image-rendering: pixelated;\n  filter: drop-shadow(0 7px 0 rgba(0, 0, 0, 0.35));\n}\n.gf-results-start {\n  position: absolute;\n  right: 18px;\n  bottom: 18px;\n  z-index: 4;\n  width: 72px;\n  height: 40px;\n  object-fit: contain;\n  image-rendering: pixelated;\n  filter: drop-shadow(0 3px 0 rgba(0, 0, 0, 0.35));\n}\n\n/* ============================ PAUSE MENU ============================ */\n.gf-pause-overlay {\n  position: absolute;\n  inset: 0;\n  display: grid;\n  place-items: center;\n  background: rgba(0, 0, 0, 0.18);\n  z-index: 20;\n}\n.gf-pause-box {\n  min-width: 260px;\n  border-radius: 16px;\n  background: linear-gradient(#cfd3da, #aeb4c0);\n  border: 4px solid var(--gf-edit-purple);\n  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.5);\n  overflow: hidden;\n}\n.gf-pause-title {\n  text-align: center;\n  padding: 8px 0;\n  font-size: 22px;\n  color: var(--gf-outline);\n  letter-spacing: 0.1em;\n}\n.gf-pause-items { padding: 8px 14px 16px; display: flex; flex-direction: column; gap: 8px; }\n.gf-pause-item {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  padding: 6px 12px;\n  border-radius: 999px;\n  background: rgba(255, 255, 255, 0.4);\n  color: var(--gf-outline);\n  font-size: 18px;\n  cursor: pointer;\n  border: none;\n  font-family: inherit;\n  font-weight: 800;\n  letter-spacing: 0.06em;\n}\n.gf-pause-item.gf-selected {\n  background: linear-gradient(#6f9bd8, #2f6db0);\n  color: #fff;\n}\n.gf-pause-item .gf-pause-bullet { width: 1.4em; }\n";
